import { fn } from 'storybook/test';

import { ConfigFormFields } from './ConfigFormFields';
import type { ConfigField } from '@/lib/config-fields';
import type { Meta, StoryObj } from '@storybook/react';
import type { ComponentType } from 'react';

type Scenario =
  | 'primitive-types'
  | 'nested-types'
  | 'nested-select-or-number'
  | 'visible-when-hidden'
  | 'visible-when-shown';

interface StoryArgs {
  scenario: Scenario;
  onChange: (config: Record<string, unknown>) => void;
  // Shadowed raw props — driven by scenario; hidden from Controls.
  fields?: never;
  config?: never;
}

// Generic fixtures — one per rendering branch of ConfigFormFields.tsx.
const primitiveFields: ConfigField[] = [
  {
    type: 'select',
    key: 'size',
    label: 'Size',
    options: [
      { value: 'small', label: 'Small' },
      { value: 'medium', label: 'Medium' },
      { value: 'large', label: 'Large' },
    ],
  },
  {
    type: 'number',
    key: 'count',
    label: 'Count',
    min: 1,
    max: 20,
  },
  {
    type: 'checkbox',
    key: 'enabled',
    label: 'Enabled',
  },
];

const nestedFields: ConfigField[] = [
