      control: { type: 'radio' },
      options: [
        'picture',
        'scramble',
        'sentence-gap',
      ] satisfies Scenario[],
      description:
        'Advanced-mode preset covering meaningful WordSpell modes: picture (letters), scramble (letters with distractors), sentence-gap (word tiles).',
      if: { arg: 'mode', eq: 'advanced' },
